import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [captcha, setCaptcha] = useState("");
  const [error, setError] = useState("");

  const num1 = 5, num2 = 3;
  const captchaAnswer = num1 + num2;

  const handleLogin = () => {
    if (!email || !password || !captcha) {
      setError("All fields are required");
      return;
    }
    if (parseInt(captcha) !== captchaAnswer) {
      setError("CAPTCHA is incorrect");
      return;
    }

    setError("");
    if (email.includes("admin")) localStorage.setItem("role", "admin");
    else if (email.includes("instructor")) localStorage.setItem("role", "instructor");
    else if (email.includes("student")) localStorage.setItem("role", "student");
    else localStorage.setItem("role", "content");

    const role = localStorage.getItem("role");
    if (role === "admin") navigate("/admin");
    if (role === "instructor") navigate("/instructor");
    if (role === "student") navigate("/student");
    if (role === "content") navigate("/content");
  };

  return (
    <div className="container d-flex justify-content-center align-items-center vh-100">
      <div className="card p-4 shadow" style={{ width: "400px" }}>
        <h3 className="text-center mb-4">NexaLearn LMS</h3>

        {error && <div className="alert alert-danger">{error}</div>}

        <input
          type="email"
          className="form-control mb-3"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          className="form-control mb-3"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <input
          type="text"
          className="form-control mb-3"
          placeholder={`CAPTCHA: ${num1} + ${num2} = ?`}
          value={captcha}
          onChange={(e) => setCaptcha(e.target.value)}
        />

        <button className="btn btn-primary w-100" onClick={handleLogin}>
          Login
        </button>

        <p className="mt-3 text-center">
          Don't have an account? <a href="/register">Register</a>
        </p>
      </div>
    </div>
  );
}

export default Login;
